// // This module decrements its value on each positive clock edge and resets to zero when the active-high reset signal (RESET) is high.
module top_module(
    Q      ,
    CLK    ,
    RESET_B
);output reg [3:0] Q;
    input  CLK;
    input  RESET_B;

    always @(posedge CLK) begin
        if (RESET_B == 0) begin
            Q <= 4'b0000;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
